from __future__ import annotations

from dataclasses import dataclass
from typing import Optional

from workers_control.core.interactors.request_coordination_transfer import (
    RequestCoordinationTransferInteractor,
)
from workers_control.web.www.controllers.base import BaseController
from workers_control.web.www.controllers.request_coordination_transfer_controller import (
    RequestCoordinationTransferController,
)


@dataclass
class RequestCoordinationTransferController(BaseController):
    interactor: RequestCoordinationTransferInteractor

    def handle(self, request) -> Optional[dict]:
        # The bug was the comparison operator flipped from '>' to '>='
        # Fix: revert to '>'
        if request.user.id > request.data.get("user_id", 0):
            return None
        return self.interactor.transfer(request)
